// lib/logging/log_level.dart
enum LogLevel {
  verbose,
  debug,
  info,
  warning,
  error,
  fatal,
  none,
}

// lib/logging/log_entry.dart
class LogEntry {
  final DateTime timestamp;
  final LogLevel level;
  final String category;
  final String message;
  final Map<String, dynamic>? metadata;
  final String? errorMessage;
  final String? stackTrace;
  final String? correlationId;

  LogEntry({
    required this.level,
    required this.category,
    required this.message,
    this.metadata,
    this.errorMessage,
    this.stackTrace,
    this.correlationId,
  }) : timestamp = DateTime.now();

  Map<String, dynamic> toJson() => {
        'timestamp': timestamp.toIso8601String(),
        'level': level.name,
        'category': category,
        'message': message,
        if (metadata != null) 'metadata': metadata,
        if (errorMessage != null) 'error': errorMessage,
        if (stackTrace != null) 'stackTrace': stackTrace,
        if (correlationId != null) 'correlationId': correlationId,
      };

  @override
  String toString() =>
      '[${timestamp.toIso8601String()}] ${level.name.toUpperCase()} [$category] $message'
      '${metadata != null ? ' | metadata: $metadata' : ''}'
      '${errorMessage != null ? ' | error: $errorMessage' : ''}';
}

// lib/logging/sensitive_data_sanitizer.dart
class SensitiveDataSanitizer {
  static const _redacted = '***REDACTED***';
  static const _tokenPreviewLength = 6;

  /// Fields that should ALWAYS be fully redacted
  static const _fullyRedactedFields = {
    'password',
    'passwd',
    'pass',
    'secret',
    'credit_card',
    'creditCard',
    'card_number',
    'cardNumber',
    'cvv',
    'cvc',
    'ssn',
    'social_security',
    'pin',
    'security_answer',
    'securityAnswer',
    'private_key',
    'privateKey',
    'client_secret',
    'clientSecret',
    'api_key',
    'apiKey',
    'refresh_token',
    'refreshToken',
    'id_token',
    'idToken',
    'session_id',
    'sessionId',
    'cookie',
    'set-cookie',
  };

  /// Fields where we show a partial preview (first few chars)
  static const _partialRedactFields = {
    'token',
    'access_token',
    'accessToken',
    'authorization',
    'bearer',
    'jwt',
  };

  /// Fields containing potentially sensitive user data
  static const _piiFields = {
    'email',
    'phone',
    'phone_number',
    'phoneNumber',
    'address',
    'date_of_birth',
    'dateOfBirth',
    'dob',
  };

  /// Sanitize a map of data, redacting sensitive fields
  static Map<String, dynamic> sanitizeMap(Map<String, dynamic>? data) {
    if (data == null) return {};
    return _sanitizeMapRecursive(data);
  }

  static Map<String, dynamic> _sanitizeMapRecursive(Map<String, dynamic> data) {
    final sanitized = <String, dynamic>{};
    for (final entry in data.entries) {
      final keyLower = entry.key.toLowerCase();

      if (_fullyRedactedFields.any((f) => keyLower.contains(f.toLowerCase()))) {
        sanitized[entry.key] = _redacted;
      } else if (_partialRedactFields
          .any((f) => keyLower.contains(f.toLowerCase()))) {
        sanitized[entry.key] = _partialRedact(entry.value?.toString());
      } else if (_piiFields.any((f) => keyLower.contains(f.toLowerCase()))) {
        sanitized[entry.key] = _redactPii(entry.key, entry.value?.toString());
      } else if (entry.value is Map<String, dynamic>) {
        sanitized[entry.key] = _sanitizeMapRecursive(entry.value);
      } else if (entry.value is List) {
        sanitized[entry.key] = _sanitizeList(entry.value);
      } else {
        sanitized[entry.key] = entry.value;
      }
    }
    return sanitized;
  }

  static List<dynamic> _sanitizeList(List<dynamic> list) {
    return list.map((item) {
      if (item is Map<String, dynamic>) {
        return _sanitizeMapRecursive(item);
      }
      return item;
    }).toList();
  }

  static String _partialRedact(String? value) {
    if (value == null || value.length <= _tokenPreviewLength) {
      return _redacted;
    }
    return '${value.substring(0, _tokenPreviewLength)}...$_redacted';
  }

  static String _redactPii(String fieldName, String? value) {
    if (value == null || value.isEmpty) return _redacted;

    final keyLower = fieldName.toLowerCase();
    if (keyLower.contains('email') && value.contains('@')) {
      final parts = value.split('@');
      final localPart = parts[0];
      final domain = parts.length > 1 ? parts[1] : '';
      final maskedLocal = localPart.length > 2
          ? '${localPart.substring(0, 2)}***'
          : '***';
      return '$maskedLocal@$domain';
    }

    if (keyLower.contains('phone')) {
      if (value.length > 4) {
        return '***${value.substring(value.length - 4)}';
      }
      return _redacted;
    }

    return _redacted;
  }

  /// Sanitize HTTP headers
  static Map<String, dynamic> sanitizeHeaders(Map<String, dynamic>? headers) {
    if (headers == null) return {};
    final sanitized = <String, dynamic>{};
    for (final entry in headers.entries) {
      final keyLower = entry.key.toLowerCase();
      if (keyLower == 'authorization') {
        final val = entry.value?.toString() ?? '';
        if (val.toLowerCase().startsWith('bearer ') && val.length > 13) {
          sanitized[entry.key] = 'Bearer ${val.substring(7, 13)}...$_redacted';
        } else {
          sanitized[entry.key] = _redacted;
        }
      } else if (keyLower == 'cookie' || keyLower == 'set-cookie') {
        sanitized[entry.key] = _redacted;
      } else if (keyLower.contains('key') || keyLower.contains('secret') || keyLower.contains('token')) {
        sanitized[entry.key] = _redacted;
      } else {
        sanitized[entry.key] = entry.value;
      }
    }
    return sanitized;
  }

  /// Sanitize a URL by removing sensitive query parameters
  static String sanitizeUrl(String url) {
    try {
      final uri = Uri.parse(url);
      if (uri.queryParameters.isEmpty) return url;

      final sanitizedParams = <String, String>{};
      for (final entry in uri.queryParameters.entries) {
        final keyLower = entry.key.toLowerCase();
        if (_fullyRedactedFields.any((f) => keyLower.contains(f.toLowerCase())) ||
            _partialRedactFields.any((f) => keyLower.contains(f.toLowerCase()))) {
          sanitizedParams[entry.key] = _redacted;
        } else {
          sanitizedParams[entry.key] = entry.value;
        }
      }
      return uri.replace(queryParameters: sanitizedParams).toString();
    } catch (_) {
      return url;
    }
  }
}

// lib/logging/log_sink.dart
abstract class LogSink {
  Future<void> write(LogEntry entry);
  Future<void> flush();
  Future<void> dispose();
}

// lib/logging/console_log_sink.dart
import 'dart:convert';
import 'package:flutter/foundation.dart';

class ConsoleLogSink extends LogSink {
  final bool prettyPrint;

  ConsoleLogSink({this.prettyPrint = true});

  @override
  Future<void> write(LogEntry entry) async {
    final output = prettyPrint
        ? const JsonEncoder.withIndent('  ').convert(entry.toJson())
        : entry.toString();

    // Use debugPrint for long messages to avoid truncation
    if (output.length > 800) {
      debugPrint(output);
    } else {
      if (kDebugMode) {
        print(output);
      }
    }
  }

  @override
  Future<void> flush() async {}

  @override
  Future<void> dispose() async {}
}

// lib/logging/file_log_sink.dart
import 'dart:convert';
import 'dart:io';
import 'package:path_provider/path_provider.dart';

class FileLogSink extends LogSink {
  final String fileName;
  final int maxFileSizeBytes;
  final int maxRotatedFiles;
  IOSink? _sink;
  File? _currentFile;
  int _currentSize = 0;

  FileLogSink({
    this.fileName = 'app_log',
    this.maxFileSizeBytes = 5 * 1024 * 1024, // 5MB
    this.maxRotatedFiles = 3,
  });

  Future<void> _ensureInitialized() async {
    if (_sink != null) return;
    final dir = await getApplicationDocumentsDirectory();
    final logDir = Directory('${dir.path}/logs');
    if (!await logDir.exists()) {
      await logDir.create(recursive: true);
    }
    _currentFile = File('${logDir.path}/$fileName.log');
    if (await _currentFile!.exists()) {
      _currentSize = await _currentFile!.length();
    }
    _sink = _currentFile!.openWrite(mode: FileMode.append);
  }

  Future<void> _rotateIfNeeded() async {
    if (_currentSize < maxFileSizeBytes) return;

    await _sink?.flush();
    await _sink?.close();

    final dir = _currentFile!.parent;
    // Rotate files
    for (var i = maxRotatedFiles - 1; i >= 1; i--) {
      final older = File('${dir.path}/$fileName.$i.log');
      final newer = i == 1
          ? _currentFile!
          : File('${dir.path}/$fileName.${i - 1}.log');
      if (await newer.exists()) {
        if (i == maxRotatedFiles - 1 && await older.exists()) {
          await older.delete();
        }
        await newer.rename(older.path);
      }
    }

    _currentFile = File('${dir.path}/$fileName.log');
    _sink = _currentFile!.openWrite(mode: FileMode.write);
    _currentSize = 0;
  }

  @override
  Future<void> write(LogEntry entry) async {
    await _ensureInitialized();
    await _rotateIfNeeded();

    final line = '${jsonEncode(entry.toJson())}\n';
    _sink!.write(line);
    _currentSize += line.length;
  }

  @override
  Future<void> flush() async {
    await _sink?.flush();
  }

  @override
  Future<void> dispose() async {
    await _sink?.flush();
    await _sink?.close();
    _sink = null;
  }
}

// lib/logging/remote_log_sink.dart
import 'dart:async';
import 'dart:collection';
import 'dart:convert';
import 'package:http/http.dart' as http;

class RemoteLogSink extends LogSink {
  final String endpoint;
  final String? apiKey;
  final int batchSize;
  final Duration flushInterval;
  final Queue<LogEntry> _buffer = Queue();
  Timer? _flushTimer;
  bool _isFlushing = false;

  RemoteLogSink({
    required this.endpoint,
    this.apiKey,
    this.batchSize = 50,
    this.flushInterval = const Duration(seconds: 30),
  }) {
    _flushTimer = Timer.periodic(flushInterval, (_) => flush());
  }

  @override
  Future<void> write(LogEntry entry) async {
    _buffer.add(entry);
    if (_buffer.length >= batchSize) {
      await flush();
    }
  }

  @override
  Future<void> flush() async {
    if (_isFlushing || _buffer.isEmpty) return;
    _isFlushing = true;

    try {
      final batch = <LogEntry>[];
      while (_buffer.isNotEmpty && batch.length < batchSize) {
        batch.add(_buffer.removeFirst());
      }

      final headers = <String, String>{
        'Content-Type': 'application/json',
        if (apiKey != null) 'X-API-Key': apiKey!,
      };

      final body = jsonEncode(batch.map((e) => e.toJson()).toList());

      final response = await http
          .post(Uri.parse(endpoint), headers: headers, body: body)
          .timeout(const Duration(seconds: 10));

      if (response.statusCode >= 400) {
        // Re-queue on failure
        for (final entry in batch.reversed) {
          _buffer.addFirst(entry);
        }
      }
    } catch (_) {
      // Silently fail - logging should never crash the app
    } finally {
      _isFlushing = false;
    }
  }

  @override
  Future<void> dispose() async {
    _flushTimer?.cancel();
    await flush();
  }
}

